from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            # Return a phrase that explicitly mentions the nationality
            # e.g., "is a United States national"
            return f"is a {obj} national"
        if p == "occupation":
            # Use a more natural verb for astronauts' roles
            return f"served as a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut; describe crew membership in the mission
            return f"was a crew member of {obj}"
        if p == "dateofretirement":
            # Phrase retirement date naturally
            try:
                from datetime import datetime
                dt = datetime.strptime(obj.strip('"'), "%B %Y")
                return f"retired in {dt.strftime('%B %Y')}"
            except Exception:
                # Fallback to generic wording
                return f"retired on {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"operated by {obj}"
        if p == "commander":
            # Express that the object commanded the mission (subject)
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            # Express that the object was the backup pilot for the mission (subject)
            return f"{obj} was the backup pilot of {subj}"
        if p == "crewmembers":
            # Express crew membership relative to the mission (subject)
            return f"{obj} was a crew member of {subj}"
        if p == "leader":
            # Express that the object leads the entity (subject)
            return f"{obj} is the leader of {subj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        if p == "fossil":
            # Express that the object is a fossil found in the subject location
            return f"{obj} is a fossil from {subj}"
        # Generic fallback
        return f"is {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        # Separate mission‑role predicates from generic ones
        role_parts = []
        crew_members = []
        other_desc = []

        for t in items:
            pred_key = t.predicate.lower().replace(" ", "")
            obj_clean = t.object.strip().strip('"')
            if pred_key == "commander":
                role_parts.append(f"{obj_clean} was the commander of {subj}")
            elif pred_key == "backuppilot":
                role_parts.append(f"{obj_clean} was the backup pilot of {subj}")
            elif pred_key == "crewmembers":
                crew_members.append(obj_clean)
            else:
                other_desc.append(phrase(subj, t.predicate, t.object))

        # Add crew member descriptors, combining multiple members into one phrase
        if crew_members:
            if len(crew_members) == 1:
                role_parts.append(f"{crew_members[0]} was a crew member of {subj}")
            else:
                cm_join = ", ".join(crew_members[:-1]) + f", and {crew_members[-1]}"
                role_parts.append(f"{cm_join} were crew members of {subj}")

        # Build the sentence
        if role_parts:
            if len(role_parts) == 1:
                role_sentence = role_parts[0]
            else:
                role_sentence = ", ".join(role_parts[:-1]) + f", and {role_parts[-1]}"
            if other_desc:
                if len(other_desc) == 1:
                    other_sentence = other_desc[0]
                else:
                    other_sentence = ", ".join(other_desc[:-1]) + f", and {other_desc[-1]}"
                sent = f"{role_sentence}, and {other_sentence}."
            else:
                sent = f"{role_sentence}."
        else:
            # Fallback to generic handling (same as original)
            if not other_desc:
                sent = f"{subj}."
            elif len(other_desc) == 1:
                sent = f"{subj} {other_desc[0]}."
            else:
                body = ", ".join(other_desc[:-1])
                sent = f"{subj} {body}, and {other_desc[-1]}."
        sentences.append(sent)

    # Combine sentences for different subjects
    return " ".join(sentences)

